// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const configGet = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/get-status/result`);
  const configBody = await configGet.json();

  // Azure Automation job status is nested under properties.status
  const status = (configBody?.properties?.status || configBody?.status || '').toUpperCase();
  console.log('Azure Automation Job Status:', status);

  const inProgressStatuses = ['NEW', 'ACTIVATING', 'RUNNING', 'SUSPENDING', 'STOPPING', 'RESUMING'];

  if (inProgressStatuses.includes(status)) {
    console.log('Azure Automation runbook job is still running, retrying...');
    throw new Error('Azure Automation runbook job is still running, retrying...');
  }

  return configBody;
}
